namespace Admin_Vault.Client.Models;

public class VaultCredential
{
    public int Id { get; set; }
    public string ServiceName { get; set; } = string.Empty;
    public string Environment { get; set; } = string.Empty;
    public string SecretValue { get; set; } = string.Empty;
    public string OwnerEmail { get; set; } = string.Empty;
    public string Department { get; set; } = string.Empty;
    public string Status { get; set; } = "Active";
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;

    public string EnvColor => Environment.ToLowerInvariant() switch
    {
        "production" => "#d97706",
        "staging" => "#9333ea",
        "development" => "#2563eb",
        _ => "#6b7280"
    };

    public string BgColor => Environment.ToLowerInvariant() switch
    {
        "production" => "#f59e0b",
        "staging" => "#a855f7",
        "development" => "#3b82f6",
        _ => "#9ca3af"
    };

    public string MaskedValue
    {
        get
        {
            if (string.IsNullOrEmpty(SecretValue)) return string.Empty;
            var prefix = SecretValue.Length > 7 ? SecretValue[..7] : SecretValue;
            var suffix = SecretValue.Length > 4 ? SecretValue[^4..] : string.Empty;
            return $"{prefix}{new string('\u2022', 12)}{suffix}";
        }
    }
}

namespace Admin_Vault.Client.Models;

public class ComplianceDocument
{
    public int Id { get; set; }
    public string FileName { get; set; } = string.Empty;
    public long FileSizeBytes { get; set; }
    public string Sha256 { get; set; } = string.Empty;
    public DateTime UploadedAt { get; set; } = DateTime.UtcNow;
    public string UploadedBy { get; set; } = string.Empty;
    public string Classification { get; set; } = string.Empty;

    public string FileSizeString
    {
        get
        {
            double kb = FileSizeBytes / 1024d;
            return kb < 1024 ? $"{kb:F1} KB" : $"{kb / 1024d:F1} MB";
        }
    }

    public string ShortChecksum
    {
        get
        {
            if (string.IsNullOrEmpty(Sha256)) return string.Empty;
            return Sha256.Length > 16 ? $"{Sha256[..8]}...{Sha256[^8..]}" : Sha256;
        }
    }
}

namespace Admin_Vault.Client.Models;

public class AuditLog
{
    public int Id { get; set; }
    public DateTime Timestamp { get; set; } = DateTime.UtcNow;
    public string Action { get; set; } = string.Empty;
    public string ActorEmail { get; set; } = string.Empty;
    public string ActorRole { get; set; } = string.Empty;
    public string IpAddress { get; set; } = string.Empty;
    public string Status { get; set; } = "SUCCESS";
}

namespace Admin_Vault.Client.Models;

public class DashboardStats
{
    public int TotalCredentials { get; set; }
    public int ActiveApiKeys { get; set; }
    public int ComplianceDocuments { get; set; }
    public int AuditTriggers24h { get; set; }
    public int UnauthorizedAttempts24h { get; set; }
}

using Admin_Vault.Client.Models;

namespace Admin_Vault.Client.Services;

public interface IVaultDataService
{
    Task<DashboardStats> GetDashboardStatsAsync();
    Task<List<VaultCredential>> GetCredentialsAsync();
    Task<List<ComplianceDocument>> GetDocumentsAsync();
    Task<List<AuditLog>> GetAuditLogsAsync(int limit = 200);
    Task AddCredentialAsync(VaultCredential credential);
    Task AddDocumentAsync(ComplianceDocument document);
    Task AddAuditLogAsync(AuditLog log);
}

using Admin_Vault.Client.Models;
using Microsoft.EntityFrameworkCore;

namespace Admin_Vault.Data;

public class VaultDbContext : DbContext
{
    public VaultDbContext(DbContextOptions<VaultDbContext> options) : base(options) { }

    public DbSet<VaultCredential> Credentials => Set<VaultCredential>();
    public DbSet<ComplianceDocument> Documents => Set<ComplianceDocument>();
    public DbSet<AuditLog> AuditLogs => Set<AuditLog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<VaultCredential>().ToTable("credentials");
        modelBuilder.Entity<ComplianceDocument>().ToTable("documents");
        modelBuilder.Entity<AuditLog>().ToTable("audit_logs");
    }
}

using Npgsql;

namespace Admin_Vault.Data;

public static class DatabaseConnection
{
    /// <summary>
    /// Accepts either a libpq URI (postgres://user:pass@host:port/db, e.g. a Supabase
    /// pooler string) or an already-formatted Npgsql key/value connection string and
    /// returns a valid Npgsql connection string.
    /// </summary>
    public static string BuildNpgsqlConnectionString(string raw)
    {
        raw = raw.Trim();

        if (!raw.StartsWith("postgres://", StringComparison.OrdinalIgnoreCase) &&
            !raw.StartsWith("postgresql://", StringComparison.OrdinalIgnoreCase))
        {
            // Already a key/value connection string.
            return raw;
        }

        var uri = new Uri(raw);
        var userInfo = uri.UserInfo.Split(':', 2);

        var builder = new NpgsqlConnectionStringBuilder
        {
            Host = uri.Host,
            Port = uri.Port == -1 ? 5432 : uri.Port,
            Database = Uri.UnescapeDataString(uri.AbsolutePath.TrimStart('/')),
            Username = Uri.UnescapeDataString(userInfo[0]),
            Password = userInfo.Length > 1 ? Uri.UnescapeDataString(userInfo[1]) : null,
            SslMode = SslMode.Require,
            Pooling = true
        };

        return builder.ConnectionString;
    }
}

using Admin_Vault.Client.Models;
using Admin_Vault.Client.Services;
using Microsoft.EntityFrameworkCore;

namespace Admin_Vault.Data;

public class VaultDataService : IVaultDataService
{
    private readonly VaultDbContext _db;

    public VaultDataService(VaultDbContext db) => _db = db;

    public async Task<DashboardStats> GetDashboardStatsAsync()
    {
        var since = DateTime.UtcNow.AddHours(-24);
        return new DashboardStats
        {
            TotalCredentials = await _db.Credentials.CountAsync(),
            ActiveApiKeys = await _db.Credentials.CountAsync(c => c.Status == "Active"),
            ComplianceDocuments = await _db.Documents.CountAsync(),
            AuditTriggers24h = await _db.AuditLogs.CountAsync(a => a.Timestamp >= since),
            UnauthorizedAttempts24h = await _db.AuditLogs.CountAsync(a => a.Timestamp >= since && a.Status != "SUCCESS")
        };
    }

    public async Task<List<VaultCredential>> GetCredentialsAsync() =>
        await _db.Credentials.AsNoTracking().OrderByDescending(c => c.CreatedAt).ToListAsync();

    public async Task<List<ComplianceDocument>> GetDocumentsAsync() =>
        await _db.Documents.AsNoTracking().OrderByDescending(d => d.UploadedAt).ToListAsync();

    public async Task<List<AuditLog>> GetAuditLogsAsync(int limit = 200) =>
        await _db.AuditLogs.AsNoTracking().OrderByDescending(a => a.Timestamp).Take(limit).ToListAsync();

    public async Task AddCredentialAsync(VaultCredential credential)
    {
        credential.CreatedAt = DateTime.UtcNow;
        _db.Credentials.Add(credential);
        await _db.SaveChangesAsync();
    }

    public async Task AddDocumentAsync(ComplianceDocument document)
    {
        document.UploadedAt = DateTime.UtcNow;
        _db.Documents.Add(document);
        await _db.SaveChangesAsync();
    }

    public async Task AddAuditLogAsync(AuditLog log)
    {
        log.Timestamp = DateTime.UtcNow;
        _db.AuditLogs.Add(log);
        await _db.SaveChangesAsync();
    }
}

