@inject IJSRuntime JS

<PageTitle>API Keys & Credentials | Olyxee Vault</PageTitle>

<div class="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
    <div>
        <h2 class="text-xl font-bold text-gray-900">API Keys & Protected Secrets</h2>
        <p class="text-xs text-gray-500">Secure injection matrix for cloud service authorization tokens.</p>
    </div>
    <button @onclick="ToggleProvisionForm" class="bg-gray-900 hover:bg-gray-800 text-white text-xs font-semibold px-4 py-2.5 rounded-lg shadow-sm transition-all flex items-center gap-2 self-start sm:self-auto">
        <i data-lucide="plus" class="w-3.5 h-3.5"></i> Provision Secret
    </button>
</div>

@if (showProvisionForm)
{
    <div class="bg-white border border-gray-200 rounded-xl shadow-sm p-6 mb-6">
        <h3 class="font-bold text-base text-gray-900 mb-4">Provision New Secret</h3>
        <EditForm Model="newCredential" OnValidSubmit="HandleProvision">
            <DataAnnotationsValidator />
            <div class="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                    <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Service Name</label>
                    <input @bind="newCredential.ServiceName" required class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800" placeholder="OpenAI API Key" />
                </div>
                <div>
                    <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Environment</label>
                    <select @bind="newCredential.Environment" class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800">
                        <option>Production</option>
                        <option>Staging</option>
                        <option>Development</option>
                    </select>
                </div>
                <div class="sm:col-span-2">
                    <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Secret Value</label>
                    <input @bind="newCredential.SecretValue" required class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800 font-mono" placeholder="sk-proj-..." />
                </div>
                <div>
                    <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Owner Email</label>
                    <input @bind="newCredential.OwnerEmail" class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800" placeholder="owner@company.com" />
                </div>
                <div>
                    <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Department</label>
                    <input @bind="newCredential.Department" class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800" placeholder="Engineering" />
                </div>
            </div>
            <div class="flex items-center gap-3 mt-5">
                <button type="submit" class="bg-gray-900 hover:bg-gray-800 text-white text-xs font-semibold px-4 py-2 rounded-lg transition-all">Save Secret</button>
                <button type="button" @onclick="ToggleProvisionForm" class="text-gray-500 hover:text-gray-900 text-xs font-semibold px-3 py-2 transition-colors">Cancel</button>
            </div>
        </EditForm>
    </div>
}

<div class="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
    <div class="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-gray-50/50">
        <div>
            <h3 class="font-bold text-base text-gray-900">Active Variable Ledger</h3>
            <p class="text-xs text-gray-500">Cryptographically isolated key strings.</p>
        </div>
    </div>

    <div class="overflow-x-auto">
        <table class="w-full text-left text-xs whitespace-nowrap">
            <thead class="bg-gray-50 text-gray-500 uppercase font-semibold tracking-wider border-b border-gray-200 text-[10px]">
                <tr>
                    <th class="px-6 py-3.5">Service & Environment</th>
                    <th class="px-6 py-3.5">Secret Key Value Token</th>
                    <th class="px-6 py-3.5">Scope Owner</th>
                    <th class="px-6 py-3.5 text-right">Actions Workspace</th>
                </tr>
            </thead>
            <tbody class="divide-y divide-gray-100 text-gray-700">
                @if (CredentialsList.Count == 0)
                {
                    <tr><td colspan="4" class="px-6 py-8 text-center text-gray-400">No credentials provisioned yet.</td></tr>
                }
                else
                {
                    @foreach (var credential in CredentialsList)
                    {
                        <tr class="hover:bg-gray-50/50 transition-colors">
                            <td class="px-6 py-4">
                                <div class="font-bold text-gray-900">@credential.ServiceName</div>
                                <div class="text-[10px] font-medium flex items-center gap-1 mt-0.5" style="color: @credential.EnvColor">
                                    <span class="w-1.5 h-1.5 rounded-full" style="background-color: @credential.BgColor"></span> @credential.Environment
                                </div>
                            </td>
                            <td class="px-6 py-4 font-mono text-gray-600 select-all tracking-tight">
                                <div class="flex items-center gap-2">
                                    <span>@(revealedIds.Contains(credential.Id) ? credential.SecretValue : credential.MaskedValue)</span>
                                    <button @onclick="() => ToggleSecretReveal(credential)" class="text-gray-400 hover:text-gray-700 transition-colors p-1">
                                        <i data-lucide="@(revealedIds.Contains(credential.Id) ? "eye-off" : "eye")" class="w-3.5 h-3.5"></i>
                                    </button>
                                </div>
                            </td>
                            <td class="px-6 py-4">
                                <div class="font-medium text-gray-800">@credential.OwnerEmail</div>
                                <div class="text-[10px] text-gray-400">@credential.Department</div>
                            </td>
                            <td class="px-6 py-4 text-right">
                                <span class="bg-emerald-50 text-emerald-700 text-[10px] font-bold px-2 py-0.5 rounded-md border border-emerald-200">@credential.Status</span>
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private List<VaultCredential> CredentialsList = new();
    private HashSet<int> revealedIds = new();
    private bool showProvisionForm = false;
    private VaultCredential newCredential = new() { Environment = "Production" };

    protected override async Task OnInitializedAsync()
    {
        await LoadCredentials();
    }

    private async Task LoadCredentials()
    {
        CredentialsList = await Data.GetCredentialsAsync();
    }

    private void ToggleProvisionForm()
    {
        showProvisionForm = !showProvisionForm;
        if (showProvisionForm)
        {
            newCredential = new VaultCredential { Environment = "Production", OwnerEmail = CurrentUser.Email };
        }
    }

    private async Task HandleProvision()
    {
        await Data.AddCredentialAsync(newCredential);
        await Data.AddAuditLogAsync(new AuditLog
        {
            Action = $"Provisioned secret '{newCredential.ServiceName}' [{newCredential.Environment}]",
            ActorEmail = CurrentUser.Email,
            ActorRole = CurrentUser.Role,
            IpAddress = "\u2014",
            Status = "SUCCESS"
        });
        showProvisionForm = false;
        await LoadCredentials();
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    private async Task ToggleSecretReveal(VaultCredential target)
    {
        if (revealedIds.Contains(target.Id))
        {
            revealedIds.Remove(target.Id);
        }
        else
        {
            revealedIds.Add(target.Id);
            await Data.AddAuditLogAsync(new AuditLog
            {
                Action = $"Revealed secret '{target.ServiceName}' [{target.Environment}]",
                ActorEmail = CurrentUser.Email,
                ActorRole = CurrentUser.Role,
                IpAddress = "\u2014",
                Status = "SUCCESS"
            });
        }
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }
}

