@code {
    private string statusFeedbackMessage = string.Empty;
    private List<ComplianceDocument> Documents = new();

    protected override async Task OnInitializedAsync()
    {
        Documents = await Data.GetDocumentsAsync();
    }

    private async Task HandleFileSelection(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        // Stream the file once to compute a real SHA-256 checksum of its contents.
        await using var stream = file.OpenReadStream(maxAllowedSize: 25 * 1024 * 1024);
        using var memory = new MemoryStream();
        await stream.CopyToAsync(memory);
        var bytes = memory.ToArray();
        var checksum = Convert.ToHexString(SHA256.HashData(bytes)).ToLowerInvariant();

        var doc = new ComplianceDocument
        {
            FileName = file.Name,
            FileSizeBytes = file.Size,
            Sha256 = checksum,
            UploadedBy = CurrentUser.Email,
            Classification = "Confidential / Legal"
        };

        await Data.AddDocumentAsync(doc);
        await Data.AddAuditLogAsync(new AuditLog
        {
            Action = $"Uploaded compliance document '{file.Name}'",
            ActorEmail = CurrentUser.Email,
            ActorRole = CurrentUser.Role,
            IpAddress = "\u2014",
            Status = "SUCCESS"
        });

        Documents = await Data.GetDocumentsAsync();
        statusFeedbackMessage = $"Document '{file.Name}' securely committed to the ledger.";
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }
}

