using Admin_Vault.Client.Models;
using Microsoft.EntityFrameworkCore;

namespace Admin_Vault.Data;

public class VaultDbContext : DbContext
{
    public VaultDbContext(DbContextOptions<VaultDbContext> options) : base(options) { }

    public DbSet<Project> Projects => Set<Project>();
    public DbSet<VaultCredential> Credentials => Set<VaultCredential>();
    public DbSet<ComplianceDocument> Documents => Set<ComplianceDocument>();
    public DbSet<AuditLog> AuditLogs => Set<AuditLog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Project>(e =>
        {
            e.ToTable("projects");
            e.Ignore(p => p.KeyCount);
            e.Ignore(p => p.DocCount);
            e.Ignore(p => p.Initials);
            e.Ignore(p => p.AccentColor);
        });

        modelBuilder.Entity<VaultCredential>(e =>
        {
            e.ToTable("credentials");
            e.HasOne(c => c.Project)
                .WithMany()
                .HasForeignKey(c => c.ProjectId)
                .OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<ComplianceDocument>(e =>
        {
            e.ToTable("documents");
            e.HasOne(d => d.Project)
                .WithMany()
                .HasForeignKey(d => d.ProjectId)
                .OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<AuditLog>().ToTable("audit_logs");
    }
}

using Admin_Vault.Client.Models;
using Admin_Vault.Client.Services;
using Microsoft.EntityFrameworkCore;

namespace Admin_Vault.Data;

public class VaultDataService : IVaultDataService
{
    private readonly VaultDbContext _db;

    public VaultDataService(VaultDbContext db) => _db = db;

    public async Task<DashboardStats> GetDashboardStatsAsync()
    {
        var since = DateTime.UtcNow.AddHours(-24);
        return new DashboardStats
        {
            TotalProjects = await _db.Projects.CountAsync(),
            TotalCredentials = await _db.Credentials.CountAsync(),
            ActiveApiKeys = await _db.Credentials.CountAsync(c => c.Status == "Active"),
            ComplianceDocuments = await _db.Documents.CountAsync(),
            AuditTriggers24h = await _db.AuditLogs.CountAsync(a => a.Timestamp >= since),
            UnauthorizedAttempts24h = await _db.AuditLogs.CountAsync(a => a.Timestamp >= since && a.Status != "SUCCESS")
        };
    }

    public async Task<List<Project>> GetProjectsAsync()
    {
        var projects = await _db.Projects.AsNoTracking()
            .OrderByDescending(p => p.CreatedAt)
            .ToListAsync();

        var keyCounts = await _db.Credentials
            .GroupBy(c => c.ProjectId)
            .Select(g => new { ProjectId = g.Key, Count = g.Count() })
            .ToListAsync();

        var docCounts = await _db.Documents
            .GroupBy(d => d.ProjectId)
            .Select(g => new { ProjectId = g.Key, Count = g.Count() })
            .ToListAsync();

        foreach (var p in projects)
        {
            p.KeyCount = keyCounts.FirstOrDefault(k => k.ProjectId == p.Id)?.Count ?? 0;
            p.DocCount = docCounts.FirstOrDefault(d => d.ProjectId == p.Id)?.Count ?? 0;
        }

        return projects;
    }

    public async Task<Project?> GetProjectAsync(int id) =>
        await _db.Projects.AsNoTracking().FirstOrDefaultAsync(p => p.Id == id);

    public async Task AddProjectAsync(Project project)
    {
        project.CreatedAt = DateTime.UtcNow;
        _db.Projects.Add(project);
        await _db.SaveChangesAsync();
    }

    public async Task<List<VaultCredential>> GetCredentialsAsync() =>
        await _db.Credentials.AsNoTracking()
            .Include(c => c.Project)
            .OrderByDescending(c => c.CreatedAt)
            .ToListAsync();

    public async Task<List<VaultCredential>> GetCredentialsByProjectAsync(int projectId) =>
        await _db.Credentials.AsNoTracking()
            .Where(c => c.ProjectId == projectId)
            .OrderByDescending(c => c.CreatedAt)
            .ToListAsync();

    public async Task<List<ComplianceDocument>> GetDocumentsAsync() =>
        await _db.Documents.AsNoTracking()
            .Include(d => d.Project)
            .OrderByDescending(d => d.UploadedAt)
            .ToListAsync();

    public async Task<List<ComplianceDocument>> GetDocumentsByProjectAsync(int projectId) =>
        await _db.Documents.AsNoTracking()
            .Where(d => d.ProjectId == projectId)
            .OrderByDescending(d => d.UploadedAt)
            .ToListAsync();

    public async Task<List<AuditLog>> GetAuditLogsAsync(int limit = 200) =>
        await _db.AuditLogs.AsNoTracking().OrderByDescending(a => a.Timestamp).Take(limit).ToListAsync();

    public async Task AddCredentialAsync(VaultCredential credential)
    {
        credential.CreatedAt = DateTime.UtcNow;
        credential.Project = null;
        _db.Credentials.Add(credential);
        await _db.SaveChangesAsync();
    }

    public async Task AddDocumentAsync(ComplianceDocument document)
    {
        document.UploadedAt = DateTime.UtcNow;
        document.Project = null;
        _db.Documents.Add(document);
        await _db.SaveChangesAsync();
    }

    public async Task AddAuditLogAsync(AuditLog log)
    {
        log.Timestamp = DateTime.UtcNow;
        _db.AuditLogs.Add(log);
        await _db.SaveChangesAsync();
    }
}

﻿@page "/credentials"
@using Admin_Vault.Client.Models
@using Admin_Vault.Client.Services
@inject IVaultDataService Data
@inject IJSRuntime JS
@inject NavigationManager Nav

<PageTitle>API Keys & Credentials | Olyxee Vault</PageTitle>

<div class="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
    <div>
        <h2 class="text-xl font-bold text-gray-900">API Keys & Protected Secrets</h2>
        <p class="text-xs text-gray-500">Every secret across all projects. Search to locate a key fast.</p>
    </div>
    <a href="projects" class="bg-gray-900 hover:bg-gray-800 text-white text-xs font-semibold px-4 py-2.5 rounded-lg shadow-sm transition-all flex items-center gap-2 self-start sm:self-auto">
        <i data-lucide="folder" class="w-3.5 h-3.5"></i> Manage by Project
    </a>
</div>

<div class="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
    <div class="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-gray-50/50">
        <div>
            <h3 class="font-bold text-base text-gray-900">Active Variable Ledger</h3>
            <p class="text-xs text-gray-500">Cryptographically isolated key strings.</p>
        </div>
        <div class="relative w-full sm:w-72">
            <i data-lucide="search" class="w-3.5 h-3.5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input @bind="searchTerm" @bind:event="oninput" placeholder="Search by service, project, owner..." class="w-full bg-white border border-gray-200 text-xs pl-9 pr-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800" />
        </div>
    </div>

    <div class="overflow-x-auto">
        <table class="w-full text-left text-xs whitespace-nowrap">
            <thead class="bg-gray-50 text-gray-500 uppercase font-semibold tracking-wider border-b border-gray-200 text-[10px]">
                <tr>
                    <th class="px-6 py-3.5">Project</th>
                    <th class="px-6 py-3.5">Service & Environment</th>
                    <th class="px-6 py-3.5">Secret Key Value Token</th>
                    <th class="px-6 py-3.5">Scope Owner</th>
                    <th class="px-6 py-3.5 text-right">Status</th>
                </tr>
            </thead>
            <tbody class="divide-y divide-gray-100 text-gray-700">
                @if (FilteredCredentials.Count == 0)
                {
                    <tr><td colspan="5" class="px-6 py-8 text-center text-gray-400">No credentials match. Add keys from within a project.</td></tr>
                }
                else
                {
                    @foreach (var credential in FilteredCredentials)
                    {
                        <tr class="hover:bg-gray-50/50 transition-colors">
                            <td class="px-6 py-4">
                                @if (credential.Project != null)
                                {
                                    <a href="@($"projects/{credential.ProjectId}")" class="inline-flex items-center gap-2 group">
                                        <span class="w-6 h-6 rounded-md text-white text-[10px] font-bold flex items-center justify-center shrink-0" style="background-color: @credential.Project.AccentColor">@credential.Project.Initials</span>
                                        <span class="font-semibold text-gray-800 group-hover:text-gray-950">@credential.Project.Name</span>
                                    </a>
                                }
                                else
                                {
                                    <span class="text-gray-400">&mdash;</span>
                                }
                            </td>
                            <td class="px-6 py-4">
                                <div class="font-bold text-gray-900">@credential.ServiceName</div>
                                <div class="text-[10px] font-medium flex items-center gap-1 mt-0.5" style="color: @credential.EnvColor">
                                    <span class="w-1.5 h-1.5 rounded-full" style="background-color: @credential.BgColor"></span> @credential.Environment
                                </div>
                            </td>
                            <td class="px-6 py-4 font-mono text-gray-600 select-all tracking-tight">
                                <div class="flex items-center gap-2">
                                    <span>@(revealedIds.Contains(credential.Id) ? credential.SecretValue : credential.MaskedValue)</span>
                                    <button @onclick="() => ToggleSecretReveal(credential)" class="text-gray-400 hover:text-gray-700 transition-colors p-1">
                                        <i data-lucide="@(revealedIds.Contains(credential.Id) ? "eye-off" : "eye")" class="w-3.5 h-3.5"></i>
                                    </button>
                                </div>
                            </td>
                            <td class="px-6 py-4">
                                <div class="font-medium text-gray-800">@credential.OwnerEmail</div>
                                <div class="text-[10px] text-gray-400">@credential.Department</div>
                            </td>
                            <td class="px-6 py-4 text-right">
                                <span class="bg-emerald-50 text-emerald-700 text-[10px] font-bold px-2 py-0.5 rounded-md border border-emerald-200">@credential.Status</span>
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private List<VaultCredential> CredentialsList = new();
    private HashSet<int> revealedIds = new();
    private string searchTerm = string.Empty;

    private List<VaultCredential> FilteredCredentials =>
        string.IsNullOrWhiteSpace(searchTerm)
            ? CredentialsList
            : CredentialsList.Where(c =>
                (c.ServiceName?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false) ||
                (c.Project?.Name?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false) ||
                (c.OwnerEmail?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false) ||
                (c.Environment?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false) ||
                (c.Department?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false)
            ).ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadCredentials();
    }

    private async Task LoadCredentials()
    {
        CredentialsList = await Data.GetCredentialsAsync();
    }

    private async Task ToggleSecretReveal(VaultCredential target)
    {
        if (revealedIds.Contains(target.Id))
        {
            revealedIds.Remove(target.Id);
        }
        else
        {
            revealedIds.Add(target.Id);
            await Data.AddAuditLogAsync(new AuditLog
            {
                Action = $"Revealed secret '{target.ServiceName}' [{target.Environment}]",
                ActorEmail = CurrentUser.Email,
                ActorRole = CurrentUser.Role,
                IpAddress = "\u2014",
                Status = "SUCCESS"
            });
        }
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }
}

