        <button @onclick="ToggleCreateForm" class="bg-gray-900 hover:bg-gray-800 text-white text-xs font-semibold px-4 py-2.5 rounded-lg shadow-sm transition-all inline-flex items-center gap-2">
            <i data-lucide="plus" class="w-3.5 h-3.5"></i> New Project
        </button>
