}
else
{
    <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        @foreach (var project in ProjectsList)
        {
            <a href="@($"projects/{project.Id}")" class="group bg-white border border-gray-200 rounded-xl shadow-sm p-6 hover:shadow-md hover:border-gray-300 transition-all flex flex-col">
                <div class="flex items-start justify-between mb-4">
                    <span class="w-11 h-11 rounded-xl text-white text-sm font-bold flex items-center justify-center shrink-0" style="background-color: @project.AccentColor">@project.Initials</span>
                    @if (!string.IsNullOrWhiteSpace(project.Category))
                    {
                        <span class="bg-gray-100 text-gray-700 text-[10px] font-bold px-2 py-0.5 rounded-md border border-gray-200">@project.Category</span>
                    }
                </div>
