                    <span class="flex items-center gap-1.5"><i data-lucide="key-round" class="w-3.5 h-3.5"></i> @project.KeyCount keys</span>
                    <span class="flex items-center gap-1.5"><i data-lucide="file-text" class="w-3.5 h-3.5"></i> @project.DocCount docs</span>
                </div>
            </a>
        }
    </div>
}

@code {
    private List<Project> ProjectsList = new();
    private bool showCreateForm = false;
    private Project newProject = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadProjects();
    }

    private async Task LoadProjects()
    {
        ProjectsList = await Data.GetProjectsAsync();
    }

    private void ToggleCreateForm()
    {
        showCreateForm = !showCreateForm;
        if (showCreateForm)
        {
            newProject = new Project();
        }
    }

    private async Task HandleCreate()
    {
        if (string.IsNullOrWhiteSpace(newProject.Name)) return;

        await Data.AddProjectAsync(newProject);
        await Data.AddAuditLogAsync(new AuditLog
        {
            Action = $"Created project '{newProject.Name}'",
            ActorEmail = CurrentUser.Email,
            ActorRole = CurrentUser.Role,
            IpAddress = "\u2014",
            Status = "SUCCESS"
        });
        showCreateForm = false;
        await LoadProjects();
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }
}

