                        </div>
                        <div>
                            <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Owner Email</label>
                            <input @bind="newCredential.OwnerEmail" class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800" placeholder="owner@company.com" />
                        </div>
                        <div>
                            <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Department</label>
                            <input @bind="newCredential.Department" class="w-full bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-800" placeholder="Engineering" />
                        </div>
                    </div>
                    <div class="flex items-center gap-3 mt-5">
                        <button type="submit" class="bg-gray-900 hover:bg-gray-800 text-white text-xs font-semibold px-4 py-2 rounded-lg transition-all">Save Key</button>
                        <button type="button" @onclick="ToggleProvisionForm" class="text-gray-500 hover:text-gray-900 text-xs font-semibold px-3 py-2 transition-colors">Cancel</button>
                    </div>
                </EditForm>
            </div>
        }

        <div class="overflow-x-auto">
            <table class="w-full text-left text-xs whitespace-nowrap">
                <thead class="bg-gray-50 text-gray-500 uppercase font-semibold tracking-wider border-b border-gray-200 text-[10px]">
                    <tr>
                        <th class="px-6 py-3.5">Service & Environment</th>
                        <th class="px-6 py-3.5">Secret Key Value Token</th>
                        <th class="px-6 py-3.5">Scope Owner</th>
                        <th class="px-6 py-3.5 text-right">Status</th>
                    </tr>
                </thead>
                <tbody class="divide-y divide-gray-100 text-gray-700">
                    @if (Credentials.Count == 0)
                    {
                        <tr><td colspan="4" class="px-6 py-8 text-center text-gray-400">No keys in this project yet.</td></tr>
                    }
                    else
                    {
                        @foreach (var credential in Credentials)
                        {
                            <tr class="hover:bg-gray-50/50 transition-colors">
                                <td class="px-6 py-4">
                                    <div class="font-bold text-gray-900">@credential.ServiceName</div>
                                    <div class="text-[10px] font-medium flex items-center gap-1 mt-0.5" style="color: @credential.EnvColor">
                                        <span class="w-1.5 h-1.5 rounded-full" style="background-color: @credential.BgColor"></span> @credential.Environment
                                    </div>
                                </td>
                                <td class="px-6 py-4 font-mono text-gray-600 select-all tracking-tight">
                                    <div class="flex items-center gap-2">
                                        <span>@(revealedIds.Contains(credential.Id) ? credential.SecretValue : credential.MaskedValue)</span>
                                        <button @onclick="() => ToggleSecretReveal(credential)" class="text-gray-400 hover:text-gray-700 transition-colors p-1">
                                            <i data-lucide="@(revealedIds.Contains(credential.Id) ? "eye-off" : "eye")" class="w-3.5 h-3.5"></i>
                                        </button>
                                    </div>
                                </td>
                                <td class="px-6 py-4">
                                    <div class="font-medium text-gray-800">@credential.OwnerEmail</div>
                                    <div class="text-[10px] text-gray-400">@credential.Department</div>
                                </td>
                                <td class="px-6 py-4 text-right">
                                    <span class="bg-emerald-50 text-emerald-700 text-[10px] font-bold px-2 py-0.5 rounded-md border border-emerald-200">@credential.Status</span>
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>

    <!-- DOCUMENTS -->
    <div class="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
        <div class="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-gray-50/50">
            <div>
                <h3 class="font-bold text-base text-gray-900">Documents</h3>
                <p class="text-xs text-gray-500">Files scoped to this project, with SHA-256 integrity proof.</p>
            </div>
            <div class="flex items-center gap-3 self-start sm:self-auto">
                <select @bind="uploadClassification" class="bg-white border border-gray-200 text-xs px-3 py-2 rounded-lg focus:outline-none focus:border-gray-400 text-gray-700">
                    <option>Confidential / Legal</option>
                    <option>Compliance / Regulatory</option>
                    <option>Contract</option>
                    <option>Certificate</option>
                    <option>Internal</option>
                </select>
                <label class="bg-gray-900 hover:bg-gray-800 text-white text-xs font-semibold px-4 py-2 rounded-lg shadow-sm transition-all flex items-center gap-2 cursor-pointer">
                    <i data-lucide="upload-cloud" class="w-3.5 h-3.5"></i>
                    <span>Upload</span>
                    <InputFile OnChange="HandleFileSelection" class="hidden" />
                </label>
            </div>
        </div>

        <div class="overflow-x-auto">
            <table class="w-full text-left text-xs whitespace-nowrap">
                <thead class="bg-gray-50 text-gray-500 uppercase font-semibold tracking-wider border-b border-gray-200 text-[10px]">
                    <tr>
                        <th class="px-6 py-3.5">Document File Parameters</th>
                        <th class="px-6 py-3.5">SHA-256 Checksum Signature</th>
                        <th class="px-6 py-3.5">Intake Timestamp / Actor</th>
                        <th class="px-6 py-3.5">Classification</th>
                    </tr>
                </thead>
                <tbody class="divide-y divide-gray-100 text-gray-700">
                    @if (Documents.Count == 0)
                    {
                        <tr><td colspan="4" class="px-6 py-8 text-center text-gray-400">No documents in this project yet.</td></tr>
                    }
                    else
                    {
                        @foreach (var doc in Documents)
                        {
                            <tr class="hover:bg-gray-50/50 transition-colors">
                                <td class="px-6 py-4">
                                    <div class="flex items-center gap-3">
                                        <span class="text-gray-400"><i data-lucide="file-text" class="w-5 h-5"></i></span>
                                        <div>
                                            <div class="font-bold text-gray-900">@doc.FileName</div>
                                            <div class="text-[10px] text-gray-400 mt-0.5">@doc.FileSizeString</div>
                                        </div>
                                    </div>
                                </td>
                                <td class="px-6 py-4 font-mono text-gray-500 text-[11px]">@doc.ShortChecksum</td>
                                <td class="px-6 py-4">
                                    <div class="text-gray-800 font-medium">@doc.UploadedAt.ToString("yyyy-MM-dd HH:mm")</div>
                                    <div class="text-[10px] text-gray-400">@doc.UploadedBy</div>
                                </td>
                                <td class="px-6 py-4">
                                    <span class="bg-gray-100 text-gray-800 text-[10px] font-bold px-2 py-0.5 rounded-md border border-gray-200">@doc.Classification</span>
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Project? project;
    private bool loading = true;
    private List<VaultCredential> Credentials = new();
    private List<ComplianceDocument> Documents = new();
    private HashSet<int> revealedIds = new();

    private bool showProvisionForm = false;
    private VaultCredential newCredential = new() { Environment = "Production" };
    private string uploadClassification = "Confidential / Legal";
    private string statusFeedbackMessage = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        loading = true;
        project = await Data.GetProjectAsync(Id);
        if (project != null)
        {
            await LoadData();
        }
        loading = false;
    }

    private async Task LoadData()
    {
        Credentials = await Data.GetCredentialsByProjectAsync(Id);
        Documents = await Data.GetDocumentsByProjectAsync(Id);
    }

    private void ToggleProvisionForm()
    {
        showProvisionForm = !showProvisionForm;
        if (showProvisionForm)
        {
            newCredential = new VaultCredential { Environment = "Production", OwnerEmail = CurrentUser.Email };
        }
    }

    private async Task HandleProvision()
    {
        newCredential.ProjectId = Id;
        await Data.AddCredentialAsync(newCredential);
        await Data.AddAuditLogAsync(new AuditLog
        {
            Action = $"Provisioned secret '{newCredential.ServiceName}' [{newCredential.Environment}] in project '{project?.Name}'",
            ActorEmail = CurrentUser.Email,
            ActorRole = CurrentUser.Role,
            IpAddress = "\u2014",
            Status = "SUCCESS"
        });
        showProvisionForm = false;
        await LoadData();
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    private async Task ToggleSecretReveal(VaultCredential target)
    {
        if (revealedIds.Contains(target.Id))
        {
            revealedIds.Remove(target.Id);
        }
        else
        {
            revealedIds.Add(target.Id);
            await Data.AddAuditLogAsync(new AuditLog
            {
                Action = $"Revealed secret '{target.ServiceName}' [{target.Environment}] in project '{project?.Name}'",
                ActorEmail = CurrentUser.Email,
                ActorRole = CurrentUser.Role,
                IpAddress = "\u2014",
                Status = "SUCCESS"
            });
        }
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    private async Task HandleFileSelection(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        await using var stream = file.OpenReadStream(maxAllowedSize: 25 * 1024 * 1024);
        using var memory = new MemoryStream();
        await stream.CopyToAsync(memory);
        var bytes = memory.ToArray();
        var checksum = Convert.ToHexString(SHA256.HashData(bytes)).ToLowerInvariant();

        var doc = new ComplianceDocument
        {
            ProjectId = Id,
            FileName = file.Name,
            FileSizeBytes = file.Size,
            Sha256 = checksum,
            UploadedBy = CurrentUser.Email,
            Classification = uploadClassification
        };

        await Data.AddDocumentAsync(doc);
        await Data.AddAuditLogAsync(new AuditLog
        {
            Action = $"Uploaded document '{file.Name}' to project '{project?.Name}'",
            ActorEmail = CurrentUser.Email,
            ActorRole = CurrentUser.Role,
            IpAddress = "\u2014",
            Status = "SUCCESS"
        });

        await LoadData();
        statusFeedbackMessage = $"Document '{file.Name}' securely committed to the ledger.";
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        await JS.InvokeVoidAsync("refreshTailwindAndIcons");
    }
}

