@for (int r = 0; r < Rows; r++)
{
    <tr class="border-b border-gray-100">
        @for (int c = 0; c < Columns; c++)
        {
            <td class="px-6 py-4">
                <div class="skeleton" style="height:13px; width:@ColumnWidth(c); opacity:@RowOpacity(r);"></div>
                @if (c == 0)
                {
