@code {
    [Parameter] public int Rows { get; set; } = 5;
    [Parameter] public int Columns { get; set; } = 4;

    private string ColumnWidth(int c) => c == 0 ? "62%" : (c % 2 == 0 ? "48%" : "70%");

    // Subtle vertical fade so the list feels like it is materializing
    private string RowOpacity(int r) => (1.0 - (r * 0.13)).ToString("0.00", System.Globalization.CultureInfo.InvariantCulture);
}

