@code {
    private bool sidebarOpen = false;
    private string currentPageKey = "";

    protected override void OnInitialized()
    {
        currentPageKey = NavManager.Uri;
        NavManager.LocationChanged += OnLocationChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await TriggerUIRefreshAsync();
        }
    }

    private void ToggleSidebar() => sidebarOpen = !sidebarOpen;
    private void CloseSidebar() => sidebarOpen = false;

    private string SidebarClasses =>
        "fixed lg:static inset-y-0 left-0 z-50 w-72 lg:w-64 bg-white border-r border-gray-200/70 flex flex-col justify-between shrink-0 " +
        "transform transition-transform duration-300 ease-out lg:translate-x-0 " +
        (sidebarOpen ? "translate-x-0 shadow-2xl lg:shadow-none" : "-translate-x-full");

    private string NavClass(bool active) =>
        "flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium transition-colors " +
        (active
            ? "bg-gray-900 text-white font-semibold shadow-sm"
            : "text-gray-600 hover:bg-gray-100 hover:text-gray-950");

    private async void OnLocationChanged(object? sender, LocationChangedEventArgs e)
    {
        sidebarOpen = false;
        currentPageKey = e.Location;
        StateHasChanged();

        await Task.Delay(100);
        await TriggerUIRefreshAsync();
    }

    private async Task TriggerUIRefreshAsync()
    {
        try
        {
            await JS.InvokeVoidAsync("refreshTailwindAndIcons");
        }
        catch
        {
            // Context fallbacks for standard pre-render threads
        }
    }

    private bool IsActive(string relativePath)
    {
        var currentUri = NavManager.ToBaseRelativePath(NavManager.Uri).TrimEnd('/');
        return currentUri == relativePath;
    }

    private bool IsSection(string section)
    {
        var currentUri = NavManager.ToBaseRelativePath(NavManager.Uri).TrimEnd('/');
        return currentUri == section || currentUri.StartsWith($"{section}/");
    }

    public void Dispose()
    {
        NavManager.LocationChanged -= OnLocationChanged;
    }
}

