     3→namespace Admin_Vault.Data;
     4→
     5→public static class DatabaseConnection
     6→{
     7→    /// <summary>
     8→    /// Accepts either a libpq URI (postgres://user:pass@host:port/db, e.g. a Supabase
     9→    /// pooler string) or an already-formatted Npgsql key/value connection string and
    10→    /// returns a valid Npgsql connection string.
    11→    /// </summary>
    12→    public static string BuildNpgsqlConnectionString(string raw)
    13→    {
    14→        raw = raw.Trim();
    15→
    16→        if (!raw.StartsWith("postgres://", StringComparison.OrdinalIgnoreCase) &&
    17→            !raw.StartsWith("postgresql://", StringComparison.OrdinalIgnoreCase))
    18→        {
    19→            // Already a key/value connection string.
    20→            return raw;
    21→        }
    22→
    23→        var uri = new Uri(raw);
    24→        var userInfo = uri.UserInfo.Split(':', 2);
    25→
    26→        var builder = new NpgsqlConnectionStringBuilder
    27→        {
    28→            Host = uri.Host,
    29→            Port = uri.Port == -1 ? 5432 : uri.Port,
    30→            Database = Uri.UnescapeDataString(uri.AbsolutePath.TrimStart('/')),
    31→            Username = Uri.UnescapeDataString(userInfo[0]),
    32→            Password = userInfo.Length > 1 ? Uri.UnescapeDataString(userInfo[1]) : null,
    33→            SslMode = SslMode.Require,
    34→            Pooling = true
    35→        };
    36→
    37→        return builder.ConnectionString;
    38→    }
    39→}
