    16→        return new DashboardStats
    17→        {
    18→            TotalProjects = await _db.Projects.CountAsync(),
    19→            TotalCredentials = await _db.Credentials.CountAsync(),
    20→            ActiveApiKeys = await _db.Credentials.CountAsync(c => c.Status == "Active"),
    21→            ComplianceDocuments = await _db.Documents.CountAsync(),
    22→            AuditTriggers24h = await _db.AuditLogs.CountAsync(a => a.Timestamp >= since),
    23→            UnauthorizedAttempts24h = await _db.AuditLogs.CountAsync(a => a.Timestamp >= since && a.Status != "SUCCESS")
    24→        };
    25→    }
