    27→    public async Task<List<Project>> GetProjectsAsync()
    28→    {
    29→        var projects = await _db.Projects.AsNoTracking()
    30→            .OrderByDescending(p => p.CreatedAt)
    31→            .ToListAsync();
    32→
    33→        var keyCounts = await _db.Credentials
    34→            .GroupBy(c => c.ProjectId)
    35→            .Select(g => new { ProjectId = g.Key, Count = g.Count() })
