export function maskSecret(secret: string): string {
  if (!secret) return "";
  const prefix = secret.length > 7 ? secret.slice(0, 7) : secret;
  const suffix = secret.length > 4 ? secret.slice(-4) : "";
  return `${prefix}${"\u2022".repeat(12)}${suffix}`;
}

export function formatFileSize(bytes: number): string {
  const kb = bytes / 1024;
  return kb < 1024 ? `${kb.toFixed(1)} KB` : `${(kb / 1024).toFixed(1)} MB`;
}

export function shortChecksum(sha: string): string {
  if (!sha) return "";
  return sha.length > 16 ? `${sha.slice(0, 8)}...${sha.slice(-8)}` : sha;
}

export function initials(name: string): string {
  if (!name?.trim()) return "?";
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) {
    return parts[0].length > 1
      ? parts[0].slice(0, 2).toUpperCase()
      : parts[0].toUpperCase();
  }
  return `${parts[0][0]}${parts[1][0]}`.toUpperCase();
}

const ACCENT_PALETTE = [
  "#4f46e5", "#0891b2", "#059669", "#d97706",
  "#db2777", "#7c3aed", "#2563eb", "#dc2626",
];

export function accentColor(name: string): string {
  let hash = 0;
  const s = name ?? "";
  for (let i = 0; i < s.length; i++) {
    hash = (hash << 5) - hash + s.charCodeAt(i);
    hash |= 0;
  }
  return ACCENT_PALETTE[Math.abs(hash) % ACCENT_PALETTE.length];
}

export function envColors(environment: string): { text: string; bg: string } {
  switch ((environment ?? "").toLowerCase()) {
    case "production":
      return { text: "#d97706", bg: "#fffbeb" };
    case "staging":
      return { text: "#9333ea", bg: "#faf5ff" };
    case "development":
      return { text: "#2563eb", bg: "#eff6ff" };
    default:
      return { text: "#6b7280", bg: "#f9fafb" };
  }
}

export function formatDateTime(value: string | Date): string {
  const d = typeof value === "string" ? new Date(value) : value;
  return d.toISOString().slice(0, 19).replace("T", " ");
}

export function formatDate(value: string | Date): string {
  const d = typeof value === "string" ? new Date(value) : value;
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

import postgres from "postgres";

type Sql = ReturnType<typeof postgres>;

const globalForDb = globalThis as unknown as {
  __sql?: Sql;
  __schemaReady?: Promise<void>;
};

export function getSql(): Sql {
  const connectionString = process.env.SUPABASE_DB_URL;
  if (!connectionString) {
    throw new Error(
      "SUPABASE_DB_URL is not configured. Add it in the Secrets pane to connect to Supabase."
    );
  }
  if (!globalForDb.__sql) {
    globalForDb.__sql = postgres(connectionString, {
      // Supabase transaction pooler (port 6543) does not support prepared statements.
      prepare: false,
      ssl: "require",
      max: 5,
      idle_timeout: 20,
      connect_timeout: 15,
    });
  }
  return globalForDb.__sql;
}

const SCHEMA_SQL = `
create table if not exists projects (
  id           serial primary key,
  name         text not null,
  category     text not null default '',
  description  text not null default '',
  created_at   timestamptz not null default now()
);

create table if not exists credentials (
  id            serial primary key,
  project_id    integer not null references projects(id) on delete cascade,
  service_name  text not null,
  environment   text not null default '',
  secret_value  text not null default '',
  owner_email   text not null default '',
  department    text not null default '',
  status        text not null default 'Active',
  created_at    timestamptz not null default now()
);

create table if not exists documents (
  id               serial primary key,
  project_id       integer not null references projects(id) on delete cascade,
  file_name        text not null,
  file_size_bytes  bigint not null default 0,
  sha256           text not null default '',
  uploaded_at      timestamptz not null default now(),
  uploaded_by      text not null default '',
  classification   text not null default ''
);

create table if not exists audit_logs (
  id           serial primary key,
  timestamp    timestamptz not null default now(),
  action       text not null default '',
  actor_email  text not null default '',
  actor_role   text not null default '',
  ip_address   text not null default '',
  status       text not null default 'SUCCESS'
);

create index if not exists idx_credentials_project on credentials(project_id);
create index if not exists idx_documents_project on documents(project_id);
create index if not exists idx_audit_timestamp on audit_logs(timestamp desc);
`;

export function ensureSchema(): Promise<void> {
  if (!globalForDb.__schemaReady) {
    const sql = getSql();
    globalForDb.__schemaReady = sql
      .unsafe(SCHEMA_SQL)
      .then(() => undefined)
      .catch((err) => {
        // Reset so a later request can retry schema creation.
        globalForDb.__schemaReady = undefined;
        throw err;
      });
  }
  return globalForDb.__schemaReady;
}

